85	export default function SubmitVideoComposer() {
86	  const { applicationId } = useLocalSearchParams<{ applicationId: string }>();
87	  const { show: showToast } = useToast();
88	
89	  const [state, setState] = useState<LoadState>({ kind: 'loading' });
90	  const [url, setUrl] = useState('');
91	  const [preview, setPreview] = useState<PreviewState>({ kind: 'idle' });
92	  const [affirmations, setAffirmations] = useState<Record<string, boolean>>({});
93	  const [submitting, setSubmitting] = useState(false);
94	
95	  const load = useCallback(async () => {
96	    if (!applicationId) {
97	      setState({ kind: 'error', code: 'not_found' });
98	      return;
99	    }
100	    setState({ kind: 'loading' });
101	    const { data, error } = await supabase.rpc('get_my_application_for_submit', {
102	      p_application_id: applicationId,
103	    });
104	    if (error) {
105	      console.error('get_my_application_for_submit failed', error);
106	      setState({ kind: 'error', code: 'generic' });
107	      return;
108	    }
109	    const row = data?.[0];
110	    if (!row) {
111	      setState({ kind: 'error', code: 'not_found' });
112	      return;
113	    }
114	    if (row.application_status !== 'approved') {
115	      setState({ kind: 'error', code: 'not_approved' });
116	      return;
117	    }
118	    const conditions = parsePostConditions(row.post_conditions);
119	    setState({ kind: 'ok', application: row, conditions });
120	    setAffirmations(Object.fromEntries(conditions.map((c) => [c.id, false])));
121	  }, [applicationId]);
122	
123	  useEffect(() => {
124	    void load();
125	  }, [load]);
