127	  // Debounced oEmbed fetch. A new keystroke cancels any in-flight request so
128	  // we only render the latest URL's preview. AbortController covers the
129	  // network-inflight case; the state check covers the pre-fetch delay.
130	  useEffect(() => {
131	    const trimmed = url.trim();
132	    if (trimmed.length === 0) {
133	      setPreview({ kind: 'idle' });
134	      return;
135	    }
136	    const classification = classifyVideoUrl(trimmed);
137	    if (!classification) {
138	      setPreview({ kind: 'invalid' });
139	      return;
140	    }
141	    if (classification.platform === 'instagram') {
142	      // No client-side IG oEmbed (Meta app token is not in the bundle).
143	      setPreview({ kind: 'ready', classification, preview: null });
144	      return;
145	    }
146	    setPreview({ kind: 'fetching', classification });
147	    const controller = new AbortController();
148	    const handle = setTimeout(() => {
149	      fetchTikTokOembed(trimmed, controller.signal)
150	        .then((result) => {
151	          if (controller.signal.aborted) return;
152	          setPreview({ kind: 'ready', classification, preview: result });
153	        })
154	        .catch((err) => {
155	          if (controller.signal.aborted) return;
156	          console.warn('TikTok oembed client fetch failed', err);
157	          setPreview({ kind: 'error', classification });
158	        });
159	    }, OEMBED_DEBOUNCE_MS);
160	    return () => {
161	      clearTimeout(handle);
162	      controller.abort();
163	    };
164	  }, [url]);
165	
166	  const toggleAffirmation = useCallback((id: string) => {
167	    setAffirmations((cur) => ({ ...cur, [id]: !cur[id] }));
168	  }, []);
169	
170	  const canSubmit = useMemo(() => {
171	    if (state.kind !== 'ok') return false;
172	    if (submitting) return false;
173	    const classification = classifyVideoUrl(url.trim());
174	    if (!classification) return false;
175	    for (const c of state.conditions) {
176	      if (!affirmations[c.id]) return false;
177	    }
178	    return true;
179	  }, [state, url, affirmations, submitting]);
180	
181	  const onBack = useCallback(() => {
182	    if (router.canGoBack()) router.back();
183	    else router.replace('/(creator)/applications');
184	  }, []);
185	
186	  const onSubmit = useCallback(async () => {
187	    if (!canSubmit || state.kind !== 'ok') return;
188	    setSubmitting(true);
189	    const { data, error } = await supabase.functions.invoke<{
190	      submission_id: string;
191	      platform: 'tiktok' | 'instagram';
192	    }>('submit-video', {
193	      body: {
194	        application_id: state.application.application_id,
