229	        keyboardVerticalOffset={0}
230	      >
231	        {state.kind === 'loading' ? (
232	          <View style={styles.centered}>
233	            <ActivityIndicator color={colors.ink} />
234	          </View>
235	        ) : state.kind === 'error' ? (
236	          <ErrorBody code={state.code} onBack={onBack} />
237	        ) : (
238	          <>
239	            <ScrollView
240	              contentContainerStyle={styles.scrollContent}
241	              keyboardShouldPersistTaps="handled"
242	            >
243	              <HeroCard application={state.application} />
244	              <UrlSection
245	                url={url}
246	                onChangeUrl={setUrl}
