503	type SubmitErrorCode =
504	  | 'INVALID_VIDEO_URL'
505	  | 'INCOMPLETE_AFFIRMATIONS'
506	  | 'SUBMISSION_EXISTS'
507	  | 'APPLICATION_NOT_APPROVED'
508	  | 'APPLICATION_NOT_FOUND'
509	  | 'OEMBED_UNAVAILABLE'
510	  | 'UNKNOWN';
511	
512	type DecodedError = {
513	  code: SubmitErrorCode;
514	  missing?: string[];
515	};
516	
517	async function decodeErrorCode(error: unknown): Promise<DecodedError> {
518	  const ctx = (error as { context?: unknown }).context;
519	  if (
520	    ctx &&
521	    typeof ctx === 'object' &&
522	    'status' in ctx &&
523	    typeof (ctx as { json?: unknown }).json === 'function'
524	  ) {
525	    const res = ctx as Response;
526	    try {
527	      const body = (await res.json()) as {
528	        error?: string;
529	        missing_condition_ids?: unknown;
530	      };
531	      const missing = Array.isArray(body.missing_condition_ids)
532	        ? (body.missing_condition_ids.filter((x) => typeof x === 'string') as string[])
533	        : undefined;
534	      if (
535	        body.error === 'INVALID_VIDEO_URL' ||
536	        body.error === 'INCOMPLETE_AFFIRMATIONS' ||
537	        body.error === 'SUBMISSION_EXISTS' ||
538	        body.error === 'APPLICATION_NOT_APPROVED' ||
539	        body.error === 'APPLICATION_NOT_FOUND' ||
540	        body.error === 'OEMBED_UNAVAILABLE'
541	      ) {
542	        return { code: body.error, missing };
543	      }
544	    } catch {
545	      // fall through
546	    }
547	  }
548	  return { code: 'UNKNOWN' };
549	}
