555	    setAffirmations: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
556	    setSubmitting: React.Dispatch<React.SetStateAction<boolean>>;
557	    onAlreadySubmitted: () => void;
558	    onNoLongerApproved: () => void;
