568	        variant: 'error',
569	      });
570	      return;
571	    case 'INCOMPLETE_AFFIRMATIONS':
572	      if (decoded.missing && decoded.missing.length > 0) {
573	        setAffirmations((cur) => {
574	          const next = { ...cur };
575	          for (const id of decoded.missing!) next[id] = false;
576	          return next;
577	        });
578	      }
579	      showToast({
580	        message: 'Some checklist items still need to be confirmed.',
581	        variant: 'error',
582	      });
583	      return;
584	    case 'SUBMISSION_EXISTS':
585	      showToast({
586	        message: 'You already submitted a video for this application.',
587	        variant: 'info',
588	      });
589	      onAlreadySubmitted();
590	      return;
591	    case 'APPLICATION_NOT_APPROVED':
592	      showToast({
593	        message: 'This application is no longer approved.',
594	        variant: 'error',
595	      });
596	      onNoLongerApproved();
597	      return;
598	    case 'APPLICATION_NOT_FOUND':
599	      showToast({ message: 'Application not found.', variant: 'error' });
600	      onNoLongerApproved();
601	      return;
602	    case 'OEMBED_UNAVAILABLE':
603	      showToast({
604	        message: 'TikTok is unreachable right now. Try again shortly.',
605	        variant: 'error',
606	      });
607	      return;
608	    default:
609	      showToast({ message: 'Submission failed. Try again.', variant: 'error' });
610	  }
