613	function parsePostConditions(raw: unknown): PostConditionRaw[] {
614	  if (!Array.isArray(raw)) return [];
615	  const out: PostConditionRaw[] = [];
616	  for (const entry of raw) {
617	    if (!entry || typeof entry !== 'object') continue;
618	    const r = entry as Record<string, unknown>;
619	    if (typeof r.id !== 'string' || typeof r.metric !== 'string') continue;
620	    out.push({
621	      id: r.id,
622	      metric: r.metric,
623	      operator: typeof r.operator === 'string' ? r.operator : '',
624	      numeric_threshold:
625	        typeof r.numeric_threshold === 'number' ? r.numeric_threshold : null,
626	      text_threshold:
627	        typeof r.text_threshold === 'string' ? r.text_threshold : null,
628	      bool_threshold:
629	        typeof r.bool_threshold === 'boolean' ? r.bool_threshold : null,
630	      platform:
631	        r.platform === 'tiktok' || r.platform === 'instagram' ? r.platform : null,
632	    });
633	  }
634	  return out;
635	}
