637	function postConditionLabel(c: PostConditionRaw): string {
638	  switch (c.metric) {
639	    case 'post_family_friendly':
640	      return c.bool_threshold
641	        ? 'My video is family-friendly.'
642	        : 'My video may be mature, as allowed.';
643	    case 'post_must_mention':
644	      return c.text_threshold
645	        ? `I mention "${c.text_threshold}" in the video.`
646	        : 'I include the required mention.';
647	    case 'post_must_tag_account':
648	      return c.text_threshold
649	        ? `I tag @${c.text_threshold.replace(/^@/, '')}.`
650	        : 'I tag the lister account.';
651	    case 'post_min_video_duration_sec':
652	      return c.numeric_threshold !== null
653	        ? `My video is at least ${c.numeric_threshold} seconds long.`
654	        : 'My video meets the minimum duration.';
655	    case 'post_max_video_duration_sec':
656	      return c.numeric_threshold !== null
657	        ? `My video is at most ${c.numeric_threshold} seconds long.`
658	        : 'My video is within the maximum duration.';
659	    case 'post_min_video_count':
660	      return c.numeric_threshold !== null
661	        ? `I posted at least ${c.numeric_threshold} videos.`
662	        : 'I posted the required number of videos.';
663	    default:
664	      return c.metric;
665	  }
666	}
